mapper.select:
select p.title as title, sum(o_items.quantity) as salesCount from order_items as o_items INNER JOIN orders as o on o.id = o_items.order_id INNER JOIN products as p on p.id = o_items.product_id where o.pickup_time >= CONCAT(#{periodSummaryVO.startDate}, ' 00:00:00') AND o.pickup_time <= CONCAT(#{periodSummaryVO.endDate}, ' 23:59:59') AND o.status = 2 AND p.product_type IN
#{type}
GROUP BY o_items.product_id ORDER BY salesCount DESC LIMIT 5
